#include <stdio.h>
#include <stdlib.h>

// Define the structure for a graph node
typedef struct Node {
    int data;
    struct Node* next;
} Node;

// Define the structure for a graph
typedef struct Graph {
    int numVertices;
    Node** adjLists;
} Graph;

// Function to create a new graph node
Node* createNode(int data) {
    Node* newNode = (Node*) malloc(sizeof(Node));
    if (!newNode) {
        printf("Memory error
");
        return NULL;
    }
    newNode->data = data;
    newNode->next = NULL;
    return newNode;
}

// Function to create a graph with the given number of vertices
Graph* createGraph(int numVertices) {
    Graph* graph = (Graph*) malloc(sizeof(Graph));
    if (!graph) {
        printf("Memory error
");
        return NULL;
    }
    graph->numVertices = numVertices;
    graph->adjLists = (Node**) malloc(numVertices * sizeof(Node*));
    for (int i = 0; i < numVertices; i++) {
        graph->adjLists[i] = NULL;
    }
    return graph;
}

// Function to add an edge to the graph
void addEdge(Graph* graph, int src, int dest) {
    Node* newNode = createNode(dest);
    if (graph->adjLists[src] == NULL) {
        graph->adjLists[src] = newNode;
    } else {
        Node* lastNode = graph->adjLists[src];
        while (lastNode->next) {
            lastNode = lastNode->next;
        }
        lastNode->next = newNode;
    }
}

// Function to perform DFS and topological sort
void dfs(Graph* graph, int vertex, int* visited, int* stack, int* top) {
    visited[vertex] = 1;
    Node* temp = graph->adjLists[vertex];
    while (temp) {
        if (!visited[temp->data]) {
            dfs(graph, temp->data, visited, stack, top);
        }
        temp = temp->next;
    }
    stack[(*top)++] = vertex;
}

// Function to perform topological sort
void topologicalSort(Graph* graph) {
    int* visited = (int*) malloc(graph->numVertices * sizeof(int));
    int* stack = (int*) malloc(graph->numVertices * sizeof(int));
    int top = 0;
    for (int i = 0; i < graph->numVertices; i++) {
        visited[i] = 0;
    }
    for (int i = 0; i < graph->numVertices; i++) {
        if (!visited[i]) {
            dfs(graph, i, visited, stack, &top);
        }
    }
    printf("Topological Sort: ");
    for (int i = top - 1; i >= 0; i--) {
        printf("%d ", stack[i]);
    }
    printf("\n");
}

int main() {
    int numVertices;
    printf("Enter the number of vertices: ");
    scanf("%d", &numVertices);
    Graph* graph = createGraph(numVertices);
    printf("Enter the number of edges: ");
    int numEdges;
    scanf("%d", &numEdges);
    for (int i = 0; i < numEdges; i++) {
        int src, dest;
        printf("Enter source and destination vertices: ");
        scanf("%d %d", &src, &dest);
        addEdge(graph, src, dest);
    }
    topologicalSort(graph);
    return 0;
}

